"use client";

import { useAuthActions } from "@convex-dev/auth/react";
import { useConvexAuth } from "convex/react";
import { useState, useEffect, Suspense } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import Image from "next/image";
import Link from "next/link";
import { motion, AnimatePresence } from "framer-motion";
import { Button3D } from "@/components/ui/Button3D/Button3D";
import { Input } from "@/components/ui/Input/Input";
import { Label } from "@/components/ui/Label/Label";
import styles from "./page.module.css";

type AuthMode = "signIn" | "signUp";

// Password strength calculator
function getPasswordStrength(password: string): { score: number; label: string; color: string } {
  let score = 0;
  if (password.length >= 8) score++;
  if (password.length >= 12) score++;
  if (/[a-z]/.test(password) && /[A-Z]/.test(password)) score++;
  if (/\d/.test(password)) score++;
  if (/[^a-zA-Z0-9]/.test(password)) score++;

  if (score <= 1) return { score: 1, label: "Weak", color: "#ff4444" };
  if (score <= 2) return { score: 2, label: "Fair", color: "#ffaa00" };
  if (score <= 3) return { score: 3, label: "Good", color: "#88cc00" };
  return { score: 4, label: "Strong", color: "#00cc66" };
}

// Wrapper component to handle Suspense for useSearchParams
export default function LoginPage() {
  return (
    <Suspense fallback={<div className={styles.loading}><div className={styles.spinner} /></div>}>
      <LoginPageContent />
    </Suspense>
  );
}

function LoginPageContent() {
  const { signIn } = useAuthActions();
  const { isAuthenticated, isLoading } = useConvexAuth();
  const router = useRouter();
  const searchParams = useSearchParams();
  const redirectTo = searchParams.get("redirect") || "/";

  const [mode, setMode] = useState<AuthMode>("signIn");
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const passwordStrength = getPasswordStrength(password);

  // Redirect if already authenticated
  useEffect(() => {
    if (isAuthenticated) {
      router.push(redirectTo);
    }
  }, [isAuthenticated, router, redirectTo]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError(null);

    try {
      const formData = new FormData();
      formData.set("email", email);
      formData.set("password", password);
      formData.set("flow", mode);
      if (mode === "signUp" && name) {
        formData.set("name", name);
      }

      await signIn("password", formData);
      router.push(redirectTo);
    } catch (err) {
      console.error("Auth error:", err);
      setError(
        mode === "signIn"
          ? "Invalid email or password"
          : "Failed to create account. Please try again."
      );
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleOAuth = async (provider: "github") => {
    setIsSubmitting(true);
    setError(null);
    try {
      await signIn(provider);
    } catch (err) {
      console.error("OAuth error:", err);
      setError("Sign-in failed. Please try again.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleGuestLogin = async () => {
    setIsSubmitting(true);
    setError(null);
    const guestEmail = "guest_v2@canima.com";
    const guestPassword = "GuestUser123!";
    const guestName = "Guest Viewer";

    try {
      // Try to sign in first
      const formData = new FormData();
      formData.set("email", guestEmail);
      formData.set("password", guestPassword);
      formData.set("flow", "signIn");

      await signIn("password", formData);
      router.push(redirectTo);
    } catch (signInErr) {
      console.log("Guest login failed, trying signup...", signInErr);
      // If sign in fails, try to sign up
      try {
        const formData = new FormData();
        formData.set("email", guestEmail);
        formData.set("password", guestPassword);
        formData.set("flow", "signUp");
        formData.set("name", guestName);

        await signIn("password", formData);
        router.push(redirectTo);
      } catch (signUpErr) {
        console.error("Guest signup also failed:", signUpErr);
        setError("Guest login unavailable. Please try again.");
      }
    } finally {
      setIsSubmitting(false);
    }
  };

  if (isLoading) {
    return (
      <div className={styles.loading}>
        <div className={styles.spinner} />
      </div>
    );
  }

  if (isAuthenticated) {
    return null;
  }

  return (
    <div className={styles.page}>
      <div className={styles.backButtonWrapper}>
        <Button3D 
          variant="secondary"
          onClick={() => router.push("/")}
          icon={
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
              <path d="M19 12H5M12 19l-7-7 7-7"/>
            </svg>
          }
        >
          Back to Home
        </Button3D>
      </div>

      {/* Left Panel - Hero Image */}
      <div className={styles.heroPanel}>
        <Image
          src="/login-hero.png"
          alt="Cinematic background"
          fill
          className={styles.heroImage}
          priority
        />
        <div className={styles.heroOverlay} />

        {/* Floating animated particles */}
        <div className={styles.particles}>
          {[...Array(6)].map((_, i) => (
            <motion.div
              key={i}
              className={styles.particle}
              initial={{ opacity: 0, y: 100 }}
              animate={{ 
                opacity: [0.3, 0.6, 0.3], 
                y: [-20, -100, -20],
                x: [0, (i % 2 === 0 ? 30 : -30), 0]
              }}
              transition={{ 
                duration: 8 + i * 2, 
                repeat: Infinity, 
                delay: i * 0.8,
                ease: "easeInOut"
              }}
              style={{ left: `${15 + i * 15}%`, bottom: `${10 + i * 5}%` }}
            />
          ))}
        </div>

        <motion.div 
          className={styles.heroContent}
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8, delay: 0.3 }}
        >
          <h1 className={styles.heroTitle}>
            Your Personal<br />Cinema Awaits
          </h1>
          <p className={styles.heroSubtitle}>
            Discover movies, track your favorites, and never miss what to watch next.
          </p>
          <div className={styles.featureList}>
            {[
              "Create personalized watchlists",
              "Sync across all your devices",
              "Get tailored recommendations"
            ].map((feature, i) => (
              <motion.div 
                key={i}
                className={styles.feature}
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ duration: 0.5, delay: 0.6 + i * 0.15 }}
              >
                <span className={styles.featureIcon}>✓</span>
                <span>{feature}</span>
              </motion.div>
            ))}
          </div>
        </motion.div>
      </div>

      {/* Right Panel - Auth Form */}
      <motion.div 
        className={styles.authPanel}
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ duration: 0.5 }}
      >

        <motion.div 
          className={styles.authContainer}
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6, delay: 0.2 }}
        >

          <motion.div 
            className={styles.logo}
            initial={{ scale: 0.9 }}
            animate={{ scale: 1 }}
            transition={{ duration: 0.3 }}
          >
            CANIMA
          </motion.div>

          <h2 className={styles.authTitle}>
            {mode === "signIn" ? "Welcome Back" : "Create Account"}
          </h2>
          <p className={styles.authSubtitle}>
            {mode === "signIn"
              ? "Sign in to access your watchlist and personalized recommendations"
              : "Join millions of movie lovers and start your journey"
            }
          </p>

          {/* OAuth Buttons */}
          <motion.div 
            className={styles.oauthButtons}
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.4, delay: 0.3 }}
          >
           <Button3D
              variant="secondary"
              onClick={() => handleOAuth("github")}
              disabled={isSubmitting}
              style={{ width: '100%' }}
              icon={
                <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor">
                  <path d="M12 0c-6.626 0-12 5.373-12 12 0 5.302 3.438 9.8 8.207 11.387.599.111.793-.261.793-.577v-2.234c-3.338.726-4.033-1.416-4.033-1.416-.546-1.387-1.333-1.756-1.333-1.756-1.089-.745.083-.729.083-.729 1.205.084 1.839 1.237 1.839 1.237 1.07 1.834 2.807 1.304 3.492.997.107-.775.418-1.305.762-1.604-2.665-.305-5.467-1.334-5.467-5.931 0-1.311.469-2.381 1.236-3.221-.124-.303-.535-1.524.117-3.176 0 0 1.008-.322 3.301 1.23.957-.266 1.983-.399 3.003-.404 1.02.005 2.047.138 3.006.404 2.291-1.552 3.297-1.23 3.297-1.23.653 1.653.242 2.874.118 3.176.77.84 1.235 1.911 1.235 3.221 0 4.609-2.807 5.624-5.479 5.921.43.372.823 1.102.823 2.222v3.293c0 .319.192.694.801.576 4.765-1.589 8.199-6.086 8.199-11.386 0-6.627-5.373-12-12-12z"/>
                </svg>
              }
            >
              Continue with GitHub
            </Button3D>
          </motion.div>

          {/* Divider */}
          <div className={styles.divider}>
            <span className={styles.dividerLine} />
            <span className={styles.dividerText}>or</span>
            <span className={styles.dividerLine} />
          </div>

          {/* Email Form */}
          <form onSubmit={handleSubmit} className={styles.form}>
            {/* Name field - only show in signup mode */}
            <AnimatePresence mode="wait">
              {mode === "signUp" && (
                <motion.div 
                  className={styles.field}
                  initial={{ opacity: 0, height: 0 }}
                  animate={{ opacity: 1, height: "auto" }}
                  exit={{ opacity: 0, height: 0 }}
                  transition={{ duration: 0.3 }}
                >
                  <Label htmlFor="name">
                    Name
                  </Label>
                  <Input
                    id="name"
                    type="text"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    placeholder="Your name"
                  />
                </motion.div>
              )}
            </AnimatePresence>

            <div className={styles.field}>
              <Label htmlFor="email">
                Email
              </Label>
              <Input
                id="email"
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="you@example.com"
                required
              />
            </div>

            <div className={styles.field}>
              <Label htmlFor="password">
                Password
              </Label>
              <div className={styles.passwordWrapper}>
                <Input
                  id="password"
                  type={showPassword ? "text" : "password"}
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="••••••••"
                  minLength={8}
                  required
                  style={{ paddingRight: 50 }}
                />
                <button
                  type="button"
                  className={styles.passwordToggle}
                  onClick={() => setShowPassword(!showPassword)}
                  aria-label={showPassword ? "Hide password" : "Show password"}
                >
                  {showPassword ? (
                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                      <path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24"/>
                      <line x1="1" y1="1" x2="23" y2="23"/>
                    </svg>
                  ) : (
                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                      <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/>
                      <circle cx="12" cy="12" r="3"/>
                    </svg>
                  )}
                </button>
              </div>

              {/* Password strength indicator */}
              <AnimatePresence>
                {mode === "signUp" && password.length > 0 && (
                  <motion.div
                    className={styles.passwordStrength}
                    initial={{ opacity: 0, y: -10 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, y: -10 }}
                  >
                    <div className={styles.strengthBar}>
                      {[1, 2, 3, 4].map((level) => (
                        <motion.div
                          key={level}
                          className={styles.strengthSegment}
                          initial={{ scaleX: 0 }}
                          animate={{ 
                            scaleX: passwordStrength.score >= level ? 1 : 0,
                            backgroundColor: passwordStrength.score >= level ? passwordStrength.color : "rgba(255,255,255,0.1)"
                          }}
                          transition={{ duration: 0.3, delay: level * 0.05 }}
                        />
                      ))}
                    </div>
                    <span 
                      className={styles.strengthLabel}
                      style={{ color: passwordStrength.color }}
                    >
                      {passwordStrength.label}
                    </span>
                  </motion.div>
                )}
              </AnimatePresence>
            </div>

            {error && (
              <motion.div 
                className={styles.error}
                initial={{ opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
              >
                {error}
              </motion.div>
            )}

            <Button3D
              type="submit"
              className={styles.submitButton}
              disabled={isSubmitting}
              icon={
                isSubmitting ? (
                  <div className={styles.spinner} style={{ width: 16, height: 16, borderTopColor: 'white', borderWidth: 2 }} />
                ) : null
              }
            >
              {isSubmitting
                ? "Please wait..."
                : mode === "signIn"
                ? "Sign In"
                : "Create Account"
              }
            </Button3D>

            {/* Guest Login Button (Styled as Secondary Button3D) */}
            {mode === "signIn" && (
               <div style={{ marginTop: '1rem' }}>
                  <Button3D
                    variant="secondary"
                    onClick={handleGuestLogin}
                    disabled={isSubmitting}
                    style={{ width: '100%' }}
                    icon={
                      <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                         <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"></path>
                         <circle cx="12" cy="7" r="4"></circle>
                      </svg>
                    }
                  >
                    Login as Guest
                  </Button3D>
               </div>
            )}
          </form>

          {/* Mode Switch */}
          <p className={styles.modeSwitch}>
            {mode === "signIn" ? "Don't have an account?" : "Already have an account?"}
            <button
              type="button"
              className={styles.modeSwitchButton}
              onClick={() => {
                setMode(mode === "signIn" ? "signUp" : "signIn");
                setError(null);
              }}
            >
              {mode === "signIn" ? "Sign Up" : "Sign In"}
            </button>
          </p>
        </motion.div>
      </motion.div>
    </div>
  );
}

"use client";

import { useState, useRef, useEffect } from "react";
import { useQuery, useMutation, useAction, useConvexAuth } from "convex/react";
import { useRouter } from "next/navigation";
import { api } from "../../../convex/_generated/api";
import Link from "next/link";
import { motion } from "framer-motion";
import styles from "./page.module.css";
import Image from "next/image";
import { Input } from "@/components/ui/Input/Input";
import { Label } from "@/components/ui/Label/Label";
import { Textarea } from "@/components/ui/Textarea/Textarea";
import { Button3D } from "@/components/ui/Button3D/Button3D";
import { SelectionChip } from "@/components/ui/SelectionChip/SelectionChip";
import { Avatar } from "@/components/ui/Avatar/Avatar";
import { Edit2, Mail, Calendar, Film, Star } from "lucide-react";

interface Genre {
  id: number;
  name: string;
}

export default function ProfilePage() {
  const { isAuthenticated, isLoading: isAuthLoading } = useConvexAuth();
  const router = useRouter();
  const profile = useQuery(api.profiles.getMyProfile);
  const ratingsCount = useQuery(api.ratings.getUserRatingsCount);
  const watchlistCount = useQuery(api.watchlist.getWatchlistCount);
  const updateProfile = useMutation(api.profiles.updateProfile);
  const generateUploadUrl = useMutation(api.profiles.generateUploadUrl);
  const updateAvatar = useMutation(api.profiles.updateAvatar);
  const getGenres = useAction(api.tmdb.getGenres);

  const [displayName, setDisplayName] = useState("");
  const [bio, setBio] = useState("");
  const [favoriteGenres, setFavoriteGenres] = useState<string[]>([]);
  const [country, setCountry] = useState("");
  const [isEditing, setIsEditing] = useState(false);
  const [allGenres, setAllGenres] = useState<Genre[]>([]);
  const [uploading, setUploading] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Redirect if not authenticated
  useEffect(() => {
    if (!isAuthLoading && !isAuthenticated) {
      router.push("/");
    }
  }, [isAuthLoading, isAuthenticated, router]);

  // Initialize form data
  useEffect(() => {
    if (profile) {
      setDisplayName(profile.displayName || "");
      setBio(profile.bio || "");
      setFavoriteGenres(profile.favoriteGenres || []);
      setCountry(profile.country || "");
    }
  }, [profile]);

  // Fetch genres
  useEffect(() => {
    async function fetchGenres() {
      try {
        const data = await getGenres({ mediaType: "movie" });
        setAllGenres((data as { genres: Genre[] }).genres);
      } catch (err) {
        console.error("Failed to fetch genres", err);
      }
    }
    fetchGenres();
  }, [getGenres]);

  const handleAvatarClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setUploading(true);
    try {
      const postUrl = await generateUploadUrl();
      const result = await fetch(postUrl, {
        method: "POST",
        headers: { "Content-Type": file.type },
        body: file,
      });

      if (!result.ok) throw new Error("Upload failed");
      const { storageId } = await result.json();
      await updateAvatar({ storageId });
    } catch (error) {
      console.error("Failed to upload avatar:", error);
      alert("Failed to upload avatar. Please try again.");
    } finally {
      setUploading(false);
    }
  };

  const handleSubmit = async () => {
    setIsEditing(true);
    try {
      await updateProfile({
        displayName,
        bio,
        favoriteGenres,
        country,
      });
      setIsEditing(false); // Exit edit mode on success
    } catch (error) {
      console.error("Failed to update profile:", error);
      alert("Failed to update profile. Please try again.");
      setIsEditing(false);
    }
  };

  const toggleGenre = (genreName: string) => {
    if (favoriteGenres.includes(genreName)) {
      setFavoriteGenres(favoriteGenres.filter(g => g !== genreName));
    } else {
      if (favoriteGenres.length >= 5) {
        alert("You can select up to 5 favorite genres");
        return;
      }
      setFavoriteGenres([...favoriteGenres, genreName]);
    }
  };

  if (isAuthLoading || profile === undefined) {
    return (
      <div className={styles.loading}>
        <div className={styles.spinner} />
      </div>
    );
  }

  // if (!profile) return null; // Removed to allow empty state rendering

  return (
    <main className={styles.main}>
      {/* Hero Banner */}
      <div className={styles.heroBanner}>
        <Image
          src="/login-hero.png" // Reusing the high-quality login hero
          alt="Profile Banner"
          fill
          className={styles.heroImage}
        />
        <div className={styles.heroOverlay} />
      </div>

      <div className={styles.container}>
        <motion.div 
          className={styles.profileCard}
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
        >
          {/* Header Section */}
          <div className={styles.header}>
            <div className={styles.avatarSection}>
              <div onClick={handleAvatarClick} style={{ position: 'relative', width: 'fit-content', cursor: 'pointer' }}>
                <Avatar 
                  src={profile?.avatarUrl} 
                  fallback={displayName || "User"} 
                  size="xl"
                  className={styles.profileAvatar}
                />
                <div className={styles.uploadOverlay}>
                  <Edit2 size={24} />
                  <span>Change</span>
                  {uploading && <span>...</span>}
                </div>
              </div>
              <input
                type="file"
                ref={fileInputRef}
                className={styles.uploadInput}
                style={{ display: 'none' }}
                accept="image/*"
                onChange={handleFileChange}
              />
            </div>

            <div className={styles.headerInfo}>
              <h1 className={styles.displayName}>
                {displayName || "Movie Fan"}
              </h1>
              <div className={styles.email}>
                <Mail size={14} />
                {profile?.email || "No Email"}
                <span style={{ margin: '0 8px', opacity: 0.3 }}>|</span>
                <Calendar size={14} />
                Joined {new Date(profile?.createdAt || Date.now()).toLocaleDateString()}
              </div>

              <div className={styles.statsRow}>
                <div className={styles.statItem}>
                  <span className={styles.statValue}>{watchlistCount ?? 0}</span>
                  <span className={styles.statLabel}>Watchlist</span>
                </div>
                <div className={styles.statItem}>
                  <span className={styles.statValue}>{ratingsCount ?? 0}</span>
                  <span className={styles.statLabel}>Ratings</span>
                </div>
              </div>
            </div>

            <div className={styles.controls}>
               <Button3D
                  variant={isEditing ? "secondary" : "primary"}
                  onClick={handleSubmit}
                  disabled={uploading}
                  icon={isEditing ? <Edit2 size={16} /> : undefined}
                >
                  {isEditing ? "Saving..." : "Save Changes"}
                </Button3D>
            </div>
          </div>

          {/* Form Content */}
          <div className={styles.formGrid}>

            {/* Left Col: Personal Info */}
            <div className={styles.fields}>
              <h2 className={styles.sectionTitle}>
                <UserIcon /> Personal Details
              </h2>

              <div className={styles.field}>
                <Label>Display Name</Label>
                <Input
                  value={displayName}
                  onChange={(e) => setDisplayName(e.target.value)}
                  placeholder="Your Name"
                />
              </div>

              <div className={styles.field}>
                <Label>Bio</Label>
                <Textarea
                  value={bio}
                  onChange={(e) => setBio(e.target.value)}
                  placeholder="Tell us about yourself..."
                  rows={4}
                />
              </div>

              <div className={styles.field}>
                <Label>Country</Label>
                <Input
                  value={country}
                  onChange={(e) => setCountry(e.target.value)}
                  placeholder="e.g. United States"
                />
              </div>
            </div>

            {/* Right Col: Preferences */}
            <div>
              <h2 className={styles.sectionTitle}>
                <Star size={20} fill="currentColor" /> Favorites
              </h2>

              <div className={styles.genresSection}>
                <Label style={{ marginBottom: '1rem', display: 'block' }}>
                  Favorite Genres (Max 5)
                </Label>
                <div className={styles.genreGrid}>
                  {allGenres.map((genre) => (
                    <SelectionChip
                      key={genre.id}
                      label={genre.name}
                      selected={favoriteGenres.includes(genre.name)}
                      onClick={() => toggleGenre(genre.name)}
                    />
                  ))}
                </div>
              </div>
            </div>

          </div>
        </motion.div>
      </div>
    </main>
  );
}

function UserIcon() {
  return (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"></path>
      <circle cx="12" cy="7" r="4"></circle>
    </svg>
  );
}

"use client";

import { MovieCard } from "@/components/ui/MovieCard";
import { FilterDrawer, type FilterState } from "@/components/ui/FilterDrawer";
import { useState, useCallback, useEffect, useRef, Suspense } from "react";
import { useQuery, useMutation, useAction } from "convex/react";
import { useRouter, useSearchParams } from "next/navigation";
import { api } from "../../../convex/_generated/api";
import { motion, AnimatePresence } from "framer-motion";
import styles from "./page.module.css";
import { Input } from "@/components/ui/Input/Input";
import { SelectionChip } from "@/components/ui/SelectionChip/SelectionChip";
import { SegmentedControl } from "@/components/ui/SegmentedControl/SegmentedControl";

interface TMDBResult {
  id: number;
  title?: string;
  name?: string;
  poster_path: string | null;
  vote_average: number;
  media_type: "movie" | "tv" | "person";
  release_date?: string;
  first_air_date?: string;
  overview?: string;
}

interface TMDBResponse {
  results: TMDBResult[];
  page: number;
  total_pages: number;
  total_results: number;
}

type FilterType = "all" | "movie" | "tv";
type SearchMode = "regular" | "ai" | "canimasync";

// Wrapper component with Suspense for useSearchParams
export default function SearchPage() {
  return (
    <Suspense fallback={<><main className={styles.main}><div className={styles.loading}><div className={styles.spinner} /></div></main></>}>
      <SearchPageContent />
    </Suspense>
  );
}

function SearchPageContent() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const [query, setQuery] = useState("");
  const [results, setResults] = useState<TMDBResult[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [hasSearched, setHasSearched] = useState(false);
  const [filter, setFilter] = useState<FilterType>("all"); // "all" | "movie" | "tv"
  const [searchMode, setSearchMode] = useState<SearchMode>("regular");
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [page, setPage] = useState(1);
  const [totalResults, setTotalResults] = useState(0);
  const [hasMore, setHasMore] = useState(false);

  // Advanced Filters (Time-to-kill etc.)
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [advancedFilters, setAdvancedFilters] = useState<FilterState>({
    minRating: 0,
    sortBy: "popularity.desc",
    withGenres: "",
    maxRuntime: 0,
  });

  // AI search state
  const [aiResults, setAiResults] = useState<{ title: string; year?: number; reason: string }[]>([]);
  const [aiLoading, setAiLoading] = useState(false);

  const inputRef = useRef<HTMLInputElement>(null);
  const suggestionsRef = useRef<HTMLDivElement>(null);
  const observerRef = useRef<HTMLDivElement>(null);

  // Convex queries & actions
  const suggestions = useQuery(
    api.searchQueries.getAutocompleteSuggestions,
    query.length >= 2 ? { prefix: query } : "skip"
  );
  const popularSearches = useQuery(api.searchQueries.getPopularSearches, { limit: 5 });
  const saveSearchHistory = useMutation(api.searchQueries.saveSearchHistory);
  const trackSearchHit = useMutation(api.stats.trackSearchHit);
  const recommendMovies = useAction(api.ai.recommendMovies);

  // Discovery actions (for advanced filters)
  const getMovies = useAction(api.tmdb.getMovies);
  const getSeries = useAction(api.tmdb.getSeries);

  // Helper to check if using discovery mode (any filter active or explicit filtered search)
  const isDiscoveryMode = useCallback(() => {
    return (
      advancedFilters.minRating > 0 || 
      advancedFilters.withGenres !== "" || 
      (advancedFilters.maxRuntime !== undefined && advancedFilters.maxRuntime > 0) ||
      advancedFilters.sortBy !== "popularity.desc"
    );
  }, [advancedFilters]);

  // Handle URL search params
  useEffect(() => {
    const q = searchParams.get("q");
    if (q) {
        setQuery(q);
        // If coming from AI Search or another page, we want to trigger search immediately
        // BUT we need to ensure we don't double-trigger if user is just typing
        // Logic: If query param exists and differs from current results, or if we haven't searched yet.
        handleSearch(q, 1);
    }
  }, [searchParams]); // Dependent on searchParams only

  // Trending movies for initial state
  const [trending, setTrending] = useState<TMDBResult[]>([]);

  useEffect(() => {
    const fetchTrending = async () => {
      try {
        const apiKey = process.env.NEXT_PUBLIC_TMDB_API_KEY;
        const res = await fetch(
          `https://api.themoviedb.org/3/trending/all/week?api_key=${apiKey}`
        );
        const data = await res.json();
        setTrending(data.results?.slice(0, 10) || []);
      } catch (err) {
        console.error("Failed to fetch trending:", err);
      }
    };
    fetchTrending();
  }, []);

  // Close suggestions when clicking outside
  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (
        suggestionsRef.current &&
        !suggestionsRef.current.contains(e.target as Node) &&
        inputRef.current &&
        !inputRef.current.contains(e.target as Node)
      ) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // Infinite scroll observer
  useEffect(() => {
    if (!hasMore || isLoading) return;

    const observer = new IntersectionObserver(
      (entries) => {
        if (entries[0].isIntersecting && hasSearched) {
          loadMore();
        }
      },
      { rootMargin: "200px" }
    );

    if (observerRef.current) observer.observe(observerRef.current);
    return () => observer.disconnect();
  }, [hasMore, isLoading, hasSearched]);

  const handleSearch = useCallback(async (searchQuery?: string, newPage = 1) => {
    const q = searchQuery || query;
    // Allow empty query if using filters (Discovery Mode)
    const isDiscovering = isDiscoveryMode();
    if (!q.trim() && !isDiscovering) return;

    setQuery(q);
    setIsLoading(true);
    setHasSearched(true);
    setShowSuggestions(false);
    setError(null);

    // AI Search Mode
    if (searchMode === "ai") {
      setAiLoading(true);
      try {
        const response = await recommendMovies({ query: q });
        if (response?.recommendations) {
          setAiResults(response.recommendations);
        }
      } catch (err) {
        console.error("AI search failed:", err);
        setError("AI search failed. Please try again.");
      } finally {
        setAiLoading(false);
        setIsLoading(false);
      }
      return;
    }

    // Regular Search (Text) OR Discovery (Filters)
    try {
      let data: TMDBResponse | null = null;

      if (isDiscovering && !q.trim()) {
        // --- DISCOVERY MODE (Filters Only) ---
        // If "all" is selected, we default to movies for discovery as "multi" discovery isn't a single endpoint.
        // OR we could fetch both and merge? Complex. Let's default "all" -> "movie" for discovery for simplicity
        // or force user to pick one.
        // Better UX: standard behavior, search "Movies" if filter is active.
        const targetType = filter === "tv" ? "tv" : "movie"; 

        const discoveryArgs = {
          page: newPage,
          genreIds: advancedFilters.withGenres || undefined,
          maxRuntime: advancedFilters.maxRuntime || undefined,
        };

        if (targetType === "movie") {
           const res = await getMovies(discoveryArgs);
           data = res as TMDBResponse;
        } else {
           const res = await getSeries(discoveryArgs);
           data = res as TMDBResponse;
        }

      } else {
        // --- TEXT SEARCH MODE ---
        const apiKey = process.env.NEXT_PUBLIC_TMDB_API_KEY;
        if (!apiKey) throw new Error("API key not configured");

        const mediaType = filter === "all" ? "multi" : filter;
        const res = await fetch(
          `https://api.themoviedb.org/3/search/${mediaType}?api_key=${apiKey}&query=${encodeURIComponent(q)}&include_adult=false&page=${newPage}`
        );
        if (!res.ok) throw new Error("Search failed");
        data = await res.json();
      }

      if (data) {
        let filteredResults = (data.results || []).filter((r) => r.media_type !== "person");

        // Ensure media_type is set for Discover results (API sometimes omits it on specific endpoints)
        // If discovery was used, we know the type.
        if (isDiscovering && !q.trim()) {
             const targetType = filter === "tv" ? "tv" : "movie";
             filteredResults = filteredResults.map(r => ({ ...r, media_type: targetType }));
        }

        // For non-multi searches via text, add media_type manually if missing
        if (!isDiscovering && filter !== "all") {
          filteredResults = filteredResults.map(r => ({ ...r, media_type: filter }));
        }

        if (newPage === 1) {
          setResults(filteredResults);
        } else {
          setResults(prev => [...prev, ...filteredResults]);
        }

        setPage(newPage);
        setTotalResults(data.total_results);
        setHasMore(newPage < data.total_pages);

        // Save to search history (only for text searches)
        if (newPage === 1 && q.trim()) {
          saveSearchHistory({ query: q, resultCount: data.total_results });
        }
      }
    } catch (err) {
      setError("Search failed. Please try again.");
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  }, [query, filter, searchMode, saveSearchHistory, recommendMovies, advancedFilters, isDiscoveryMode, getMovies, getSeries]);

  const loadMore = () => {
    if (!isLoading && hasMore) {
      handleSearch(query, page + 1);
    }
  };

  const handleApplyFilters = (newFilters: FilterState) => {
    setAdvancedFilters(newFilters);
    // Switch to appropriate filter type if "All" was selected, as discovery requires specific type
    if (filter === "all") {
        setFilter("movie");
    }
    // Clear query to trigger discovery mode in handleSearch
    setQuery(""); 

    // We need to trigger a search immediately with the new state.
    // React state updates are async, so we pass explicit empty query and rely on effect or just call logic.
    // Easier: Reset page and call logic after render? 
    // Or just call handleSearch("") but we need ensure advancedFilters state is updated in closure?
    // handleSearch uses the state 'advancedFilters'. 
    // We'll use a useEffect to trigger search when advancedFilters changes IF we are in a "filtering" state?
    // No, that might trigger on initial mount.
    // Let's accept that we need to wait for state.
  };

  // Trigger search when advanced filters change
  useEffect(() => {
     if (isDiscoveryMode()) {
        setPage(1); // Reset page
        handleSearch("", 1);
     }
  }, [advancedFilters]); 


  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter") {
      handleSearch();
    } else if (e.key === "Escape") {
      setShowSuggestions(false);
    }
  };

  const handleSuggestionClick = (suggestion: string) => {
    setQuery(suggestion);
    // Reset filters when searching text
    setAdvancedFilters({
        minRating: 0,
        sortBy: "popularity.desc",
        withGenres: "",
        maxRuntime: 0,
    });
    handleSearch(suggestion);
  };

  const handleItemClick = (id: number, mediaType: "movie" | "tv") => {
    trackSearchHit({ tmdbId: id, mediaType }).catch(console.error);
    router.push(`/${mediaType}/${id}`);
  };

  const handleAiResultClick = (title: string) => {
    setSearchMode("regular");
    handleSearch(title);
  };

  const handleFilterChipChange = (f: FilterType) => {
    setFilter(f);
    if (hasSearched) handleSearch(query);
  };

  const clearRecentSearches = async () => {
    // This would call a mutation to clear history

  };

  // Combine suggestions
  const allSuggestions = [
    ...(suggestions?.recent || []).map((s) => ({ type: "recent" as const, text: s })),
    ...(suggestions?.popular || []).map((s) => ({ type: "popular" as const, text: s })),
  ].filter((s, i, arr) => arr.findIndex((a) => a.text === s.text) === i);

  const showDropdown = showSuggestions && (allSuggestions.length > 0 || (query.length < 2 && popularSearches && popularSearches.length > 0));

  const handleMatch = (genreIds: number[]) => {
    // Switch to discovery, set genres, and trigger search
    setAdvancedFilters({
      minRating: 0,
      sortBy: "popularity.desc",
      withGenres: genreIds.join(","),
      maxRuntime: 0,
    });
    setSearchMode("regular");
  };

  return (
    <>
      <main className={styles.main}>
        {/* Hero Search Section */}
        <motion.section 
          className={styles.heroSection}
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
        >
          <h1 className={styles.heroTitle}>
            {searchMode === "ai" ? "Ask AI for Recommendations" : 
             searchMode === "canimasync" ? "Mix & Match" :
             "Search Movies & TV Shows"}
          </h1>
          <p className={styles.heroSubtitle}>
            {searchMode === "ai" 
              ? "Describe what you're in the mood for and get personalized suggestions"
              : searchMode === "canimasync"
              ? "Select a genre for you and one for your partner to find the perfect middle ground."
              : "Find your next favorite movie or show"
            }
          </p>

          {/* Search Mode Toggle */}
          <div style={{ marginBottom: 24 }}>
            <SegmentedControl
              options={[
                {
                  value: "regular",
                  label: (
                    <>
                      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" width="16" height="16">
                        <circle cx="11" cy="11" r="8"/>
                        <path d="M21 21l-4.35-4.35"/>
                      </svg>
                      Search
                    </>
                  )
                },
                {
                  value: "ai",
                  label: (
                    <>
                      <span className={styles.aiIcon}>✨</span>
                      AI Recommend
                    </>
                  )
                },
                {
                  value: "canimasync",
                  label: (
                    <>
                      <span className={styles.aiIcon}>🤝</span>
                      CanimaSync
                    </>
                  )
                }
              ]}
              value={searchMode}
              onChange={(val) => {
                if (val === "canimasync") {
                  router.push("/canimasync");
                } else {
                  setSearchMode(val as any);
                }
              }}
              className="inline-flex"
            />
          </div>

          {/* Search Input - Hidden in CanimaSync mode */}
          {searchMode !== "canimasync" && (
            <div className={styles.searchBox}>
              <div className={styles.searchInputWrapper}>
                <svg className={styles.searchIcon} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <circle cx="11" cy="11" r="8"/>
                  <path d="M21 21l-4.35-4.35"/>
                </svg>
                <Input
                  ref={inputRef}
                  type="text"
                  className={styles.searchInput}
                  placeholder={searchMode === "ai" 
                    ? "Try: 'Mind-bending sci-fi like Inception'" 
                    : "Search for movies, TV shows..."
                  }
                  value={query}
                  onChange={(e) => {
                    setQuery(e.target.value);
                    setShowSuggestions(true);
                  }}
                  onFocus={() => setShowSuggestions(true)}
                  onKeyDown={handleKeyDown}
                  style={{ height: '56px', paddingLeft: '52px', paddingRight: '120px', fontSize: '18px' }}
                />
                <button
                  className={styles.searchButton}
                  onClick={() => handleSearch()}
                  disabled={isLoading || (!query.trim() && !isDiscoveryMode())}
                  style={{ 
                    position: 'absolute', 
                    right: '6px', 
                    top: '50%', 
                    transform: 'translateY(-50%)', 
                    height: '46px', 
                    padding: '0 24px', 
                    borderRadius: '12px',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    zIndex: 2
                  }}
                >
                  {isLoading ? (
                    <div className={styles.buttonSpinner} />
                  ) : searchMode === "ai" ? "Ask AI" : "Search"}
                </button>

                {/* Autocomplete Dropdown */}
                <AnimatePresence>
                  {showDropdown && (
                    <motion.div 
                      ref={suggestionsRef} 
                      className={styles.suggestions}
                      initial={{ opacity: 0, y: -10 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={{ opacity: 0, y: -10 }}
                    >
                      {query.length < 2 && popularSearches && popularSearches.length > 0 && (
                        <>
                          <div className={styles.suggestionsLabel}>🔥 Trending Searches</div>
                          {popularSearches.map((s) => (
                            <button
                              key={s}
                              className={styles.suggestionItem}
                              onClick={() => handleSuggestionClick(s)}
                            >
                              <span className={styles.suggestionIcon}>🔍</span>
                              {s}
                            </button>
                          ))}
                        </>
                      )}

                      {query.length >= 2 && allSuggestions.length > 0 && (
                        <>
                          {allSuggestions.filter(s => s.type === "recent").length > 0 && (
                            <>
                              <div className={styles.suggestionsLabel}>
                                🕐 Recent
                                <button className={styles.clearButton} onClick={clearRecentSearches}>Clear</button>
                              </div>
                              {allSuggestions.filter(s => s.type === "recent").map((s) => (
                                <button
                                  key={s.text}
                                  className={styles.suggestionItem}
                                  onClick={() => handleSuggestionClick(s.text)}
                                >
                                  <span className={styles.suggestionIcon}>🕐</span>
                                  {s.text}
                                </button>
                              ))}
                            </>
                          )}
                        </>
                      )}
                    </motion.div>
                  )}
                </AnimatePresence>
              </div>
            </div>
          )}

          {/* CanimaSync Component */}
          {/* CanimaSync Component Removed - Moved to /canimasync */}

          {/* Filter Chips - Only for regular search */}
          {searchMode === "regular" && (
            <div className={styles.filterChips}>
              {(["all", "movie", "tv"] as FilterType[]).map((f) => (
                <SelectionChip
                  key={f}
                  label={f === "all" ? "All" : f === "movie" ? "Movies" : "TV Shows"}
                  selected={filter === f}
                  onClick={() => handleFilterChipChange(f)}
                />
              ))}

               <SelectionChip
                label="Filters"
                selected={isDiscoveryMode()}
                onClick={() => setIsFilterOpen(true)}
                className={isDiscoveryMode() ? "" : "!bg-black/30 !border-white/30"}
               >
                 <span style={{ marginRight: '4px' }}>⚙️</span> Filters
               </SelectionChip>
            </div>
          )}
        </motion.section>

        <section className={styles.content}>
          {error && <div className={styles.error}>{error}</div>}

          {/* Trending Section - Show when no search performed */}
          {!hasSearched && !isDiscoveryMode() && trending.length > 0 && searchMode !== "canimasync" && (
            <motion.div 
              className={styles.trendingSection}
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ delay: 0.3 }}
            >
              <h2 className={styles.sectionTitle}>🔥 Trending This Week</h2>
              <div className={styles.trendingScroll}>
                {(trending || []).map((item) => (
                  <div 
                    key={item.id} 
                    className={styles.trendingCard}
                    onClick={() => handleItemClick(item.id, item.media_type === "tv" ? "tv" : "movie")}
                  >
                    {item.poster_path && (
                      <img
                        src={`https://image.tmdb.org/t/p/w300${item.poster_path}`}
                        alt={item.title || item.name}
                        className={styles.trendingPoster}
                      />
                    )}
                    <div className={styles.trendingInfo}>
                      <span className={styles.trendingTitle}>{item.title || item.name}</span>
                      <span className={styles.trendingRating}>⭐ {item.vote_average?.toFixed(1)}</span>
                    </div>
                  </div>
                ))}
              </div>
            </motion.div>
          )}

          {/* AI Search Results */}
          {searchMode === "ai" && hasSearched && (
            <div className={styles.aiResults}>
              {aiLoading && (
                <div className={styles.aiLoading}>
                  <span className={styles.aiLoadingIcon}>✨</span>
                  AI is thinking...
                </div>
              )}

              {aiResults.length > 0 && (
                <motion.div 
                  className={styles.aiResultsList}
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                >
                  <h2 className={styles.sectionTitle}>AI Recommendations</h2>
                  {aiResults.map((rec, i) => (
                    <motion.div
                      key={i}
                      className={styles.aiResultCard}
                      initial={{ opacity: 0, x: -20 }}
                      animate={{ opacity: 1, x: 0 }}
                      transition={{ delay: i * 0.1 }}
                      onClick={() => handleAiResultClick(rec.title)}
                    >
                      <div className={styles.aiResultHeader}>
                        <span className={styles.aiResultTitle}>{rec.title}</span>
                        {rec.year && <span className={styles.aiResultYear}>({rec.year})</span>}
                      </div>
                      <p className={styles.aiResultReason}>{rec.reason}</p>
                      <span className={styles.aiResultAction}>Click to search →</span>
                    </motion.div>
                  ))}
                </motion.div>
              )}
            </div>
          )}

          {/* Regular Search Results */}
          {searchMode === "regular" && hasSearched && (
            <>
              {/* Result Count */}
              {results.length > 0 && (
                <div className={styles.resultInfo}>
                  <span className={styles.resultCount}>
                    Found {totalResults.toLocaleString()} results 
                    {query ? ` for "${query}"` : " matching filters"}
                  </span>
                </div>
              )}

              {results.length === 0 && !isLoading && (
                <div className={styles.noResults}>
                  No results found {query ? `for "${query}"` : "matching your filters"}
                </div>
              )}

              <motion.div 
                className={styles.grid}
                initial="hidden"
                animate="visible"
                variants={{
                  hidden: { opacity: 0 },
                  visible: {
                    opacity: 1,
                    transition: { staggerChildren: 0.05 }
                  }
                }}
              >
                <AnimatePresence>
                  {results.map((item, index) => (
                    <motion.div
                      key={`${item.id}-${index}`}
                      variants={{
                        hidden: { opacity: 0, scale: 0.9 },
                        visible: { opacity: 1, scale: 1 }
                      }}
                      layout
                    >
                      <MovieCard
                        id={item.id}
                        title={item.title || item.name || ""}
                        posterPath={item.poster_path}
                        voteAverage={item.vote_average}
                        mediaType={item.media_type === "tv" ? "tv" : "movie"}
                        releaseDate={item.release_date || item.first_air_date}
                        onClick={() => handleItemClick(
                          item.id,
                          item.media_type === "tv" ? "tv" : "movie"
                        )}
                      />
                    </motion.div>
                  ))}
                </AnimatePresence>
              </motion.div>

              {/* Infinite scroll observer */}
              <div ref={observerRef} className={styles.loadMoreTrigger}>
                {isLoading && hasSearched && (
                  <div className={styles.loadingMore}>
                    <div className={styles.spinner} />
                    <span>Loading more...</span>
                  </div>
                )}
              </div>
            </>
          )}
        </section>
      </main>

      <FilterDrawer
        isOpen={isFilterOpen}
        onClose={() => setIsFilterOpen(false)}
        onApply={handleApplyFilters}
        mediaType={filter === "tv" ? "tv" : "movie"}
        initialFilters={advancedFilters}
      />
    </>
  );
}

