"use client";

import { useState, useEffect, useRef } from "react";
import Image from "next/image";
import dynamic from "next/dynamic";
import { motion, AnimatePresence } from "framer-motion";
import { Volume2, VolumeX, X, Heart, Info, Star } from "lucide-react";
import styles from "./CanimaSyncCard.module.css";

// Dynamic import for ReactPlayer to avoid SSR issues
const ReactPlayer = dynamic(() => import("react-player"), { ssr: false }) as any;

interface CanimaSyncCardProps {
  movie: {
    title: string;
    overview: string;
    posterPath?: string | null;
    voteAverage?: number;
    releaseDate?: string;
    runtime?: number;
    videos?: { site: string; type: string; key: string }[];
  };
  isActive: boolean;
  onVote: (vote: "like" | "dislike") => void;
  onInfo: () => void;
  muted: boolean;
  onToggleMute: () => void;
  votingStats?: {
    count: number;
    profiles: Array<{ name: string; avatar: string }>; // Or just basic user info
  };
}

export function CanimaSyncCard({ 
  movie, 
  isActive, 
  onVote, 
  onInfo, 
  muted, 
  onToggleMute,
  votingStats 
}: CanimaSyncCardProps) {
  const [trailerUrl, setTrailerUrl] = useState<string | null>(null);
  const [videoReady, setVideoReady] = useState(false);
  const [showVideo, setShowVideo] = useState(false);

  // Find trailer on mount
  useEffect(() => {
    if (movie.videos) {
      const trailer = movie.videos.find(
        (v) => v.site === "YouTube" && (v.type === "Trailer" || v.type === "Teaser")
      );
      if (trailer) {
        setTrailerUrl(`https://www.youtube.com/watch?v=${trailer.key}`);
      }
    }
  }, [movie]);

  // Delay showing video to allow poster to show first (smooth transition)
  useEffect(() => {
    if (isActive && trailerUrl) {
      const timer = setTimeout(() => {
        setShowVideo(true);
      }, 500); // 0.5s delay before trying to show video layer
      return () => clearTimeout(timer);
    } else {
      setShowVideo(false);
      setVideoReady(false);
    }
  }, [isActive, trailerUrl]);



  return (
    <div className={styles.card}>
      {/* Sound Toggle */}
      <button className={styles.soundToggle} onClick={(e) => { e.stopPropagation(); onToggleMute(); }}>
        {muted ? <VolumeX size={20} /> : <Volume2 size={20} />}
      </button>

      {/* Video Layer */}
      {isActive && trailerUrl && showVideo && (
        <div className={styles.videoLayer} style={{opacity: videoReady ? 1 : 0, transition: 'opacity 0.5s'}}>
           <ReactPlayer
              url={trailerUrl}
              width="100%"
              height="100%"
              playing={isActive}
              muted={muted}
              loop={true}
              controls={false}
              onReady={() => setVideoReady(true)}
              config={{
                youtube: {
                  playerVars: { showinfo: 0, controls: 0, modestbranding: 1, rel: 0, iv_load_policy: 3, autoplay: 1, playsinline: 1 }
                }
              }}
              style={{pointerEvents: 'none', transform: 'scale(1.3)'}} // Zoom in slightly to avoid black bars
           />
        </div>
      )}

      {/* Poster Layer (Background) - Always rendered but hidden if video playing */}
      <div className={`${styles.posterLayer} ${videoReady ? styles.hidden : ''}`}>
        {movie.posterPath ? (
           <Image
             src={`https://image.tmdb.org/t/p/original${movie.posterPath}`}
             alt={movie.title}
             fill
             style={{objectFit: 'cover'}}
             priority={isActive}
           />
        ) : (
          <div style={{width:'100%', height:'100%', background: '#222'}} />
        )}
      </div>

      {/* Gradient Overlay */}
      <div className={styles.overlay} />

      {/* Content & Controls */}
      <div className={styles.contentLayer}>
        <div className={styles.header}>
          <h2 className={styles.title}>{movie.title}</h2>
          <div className={styles.metaRow}>
            <div className={styles.ratingBadge}>
              {movie.voteAverage?.toFixed(1)}
            </div>
            <span className={styles.metaText}>{movie.releaseDate?.split('-')[0]}</span>
            {movie.runtime && <span className={styles.metaText}>{Math.floor(movie.runtime / 60)}h {movie.runtime % 60}m</span>}
          </div>
        </div>

        <p className={styles.description}>
          {movie.overview}
        </p>

        {/* Real-time Voting Stats */}
        {votingStats && votingStats.count > 0 && (
          <div className={styles.votingStats}>
            <Heart size={14} style={{color: '#ef4444'}} fill="#ef4444" />
            <div className={styles.avatars}>
              {votingStats.profiles.slice(0, 3).map((p, i) => (
                <div key={i} className={styles.avatar} style={{zIndex: 3-i}}>
                   {p.name.charAt(0)}
                </div>
              ))}
            </div>
            <span className={styles.voteText}>
              {votingStats.count} {votingStats.count === 1 ? 'person' : 'people'} liked this
            </span>
          </div>
        )}

        <div className={styles.controls}>
          <button className={`${styles.actionBtn} ${styles.dislikeBtn}`} onClick={() => onVote("dislike")}>
            <X size={28} />
          </button>

          <button className={styles.infoBtn} onClick={onInfo}>
             <Info size={18} />
             <span>Details</span>
          </button>

          <button className={`${styles.actionBtn} ${styles.likeBtn}`} onClick={() => onVote("like")}>
            <Heart size={28} fill="currentColor" />
          </button>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import { useAction, useMutation } from "convex/react";
import { api } from "../../../convex/_generated/api";
import styles from "./CanimaSyncLobby.module.css";
import { motion } from "framer-motion";
import { Users, Smartphone, Film, Zap, Copy, Check, ArrowRight } from "lucide-react";
import { Button3D } from "../ui/Button3D/Button3D";
import { Input } from "../ui/Input/Input";
import { Label } from "../ui/Label/Label";
import { SegmentedControl } from "../ui/SegmentedControl/SegmentedControl";
import { SelectionChip } from "../ui/SelectionChip/SelectionChip";

interface CanimaSyncLobbyProps {
  onJoin: (roomId: string, userId: string, isHost: boolean) => void;
}

export function CanimaSyncLobby({ onJoin }: CanimaSyncLobbyProps) {
  const [mode, setMode] = useState<"create" | "join">("create");
  const [userName, setUserName] = useState("");
  const [roomCode, setRoomCode] = useState("");
  const [selectedGenres, setSelectedGenres] = useState<number[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [mediaType, setMediaType] = useState<"movie" | "tv">("movie");
  const [selectedProviders, setSelectedProviders] = useState<string[]>([]);

  const createRoom = useMutation(api.canimasync.createRoom);
  const joinRoom = useMutation(api.canimasync.joinRoom);

  const PROVIDERS = [
    { id: "8", name: "Netflix" },
    { id: "119", name: "Prime Video" },
    { id: "122", name: "Hotstar" },
    { id: "220", name: "JioCinema" },
    { id: "237", name: "SonyLIV" },
    { id: "232", name: "Zee5" },
  ];

  const POPULAR_MOVIE_GENRES = [
    { id: 28, name: "Action" },
    { id: 12, name: "Adventure" },
    { id: 35, name: "Comedy" },
    { id: 18, name: "Drama" },
    { id: 878, name: "Sci-Fi" },
    { id: 27, name: "Horror" },
    { id: 53, name: "Thriller" },
    { id: 10749, name: "Romance" },
  ];

  const POPULAR_TV_GENRES = [
    { id: 10759, name: "Action & Adventure" },
    { id: 35, name: "Comedy" },
    { id: 18, name: "Drama" },
    { id: 10765, name: "Sci-Fi & Fantasy" },
    { id: 9648, name: "Mystery" },
    { id: 10764, name: "Reality" },
    { id: 16, name: "Animation" },
    { id: 99, name: "Documentary" },
  ];

  const currentGenres = mediaType === "movie" ? POPULAR_MOVIE_GENRES : POPULAR_TV_GENRES;

  const handleCreate = async () => {
    if (!userName || selectedGenres.length === 0) return;
    setIsSubmitting(true);
    try {
      const { roomId, userId } = await createRoom({
        hostName: userName,
        genres: selectedGenres,
        providers: selectedProviders,
        mediaType
      });
      onJoin(roomId, userId, true);
    } catch (err) {
      console.error(err);
      alert("Failed to create room");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleJoin = async () => {
    if (!userName || !roomCode) return;
    setIsSubmitting(true);
    try {
      const { userId } = await joinRoom({
        roomId: roomCode.toUpperCase(),
        userName
      });
      onJoin(roomCode.toUpperCase(), userId, false);
    } catch (err) {
      console.error(err);
      alert("Failed to join room. Check the code!");
    } finally {
      setIsSubmitting(false);
    }
  };

  const toggleGenre = (id: number) => {
    if (selectedGenres.includes(id)) {
      setSelectedGenres(selectedGenres.filter(g => g !== id));
    } else {
      setSelectedGenres([...selectedGenres, id]);
    }
  };

  const toggleProvider = (id: string) => {
    if (selectedProviders.includes(id)) {
      setSelectedProviders(selectedProviders.filter(p => p !== id));
    } else {
      setSelectedProviders([...selectedProviders, id]);
    }
  };

  return (
    <div className={styles.container}>
      {/* Visual Hook (Left Panel) */}
      <div className={styles.leftPanel}>
        <div className={`${styles.orb} ${styles.orb1}`} />
        <div className={`${styles.orb} ${styles.orb2}`} />

        <div className={styles.leftContent}>
            <div className={styles.logo}>
                <Zap fill="currentColor" /> CanimaSync
            </div>
            <h1 className={styles.heroTitle}>
                Swipe.<br/>Match.<br/>Watch.
            </h1>
            <p className={styles.heroSubtitle}>
                Stop arguing over what to watch. Find the perfect movie or show in seconds.
            </p>

            <div className={styles.steps}>
                <div className={styles.step}>
                    <div className={styles.stepNumber}>1</div>
                    <div className={styles.stepContent}>
                        <h3>Create a Room</h3>
                        <p>Choose your genres and streaming services.</p>
                    </div>
                </div>
                <div className={styles.step}>
                    <div className={styles.stepNumber}>2</div>
                    <div className={styles.stepContent}>
                        <h3>Invite Friends</h3>
                        <p>Share the 4-digit code. Works on any device.</p>
                    </div>
                </div>
                <div className={styles.step}>
                    <div className={styles.stepNumber}>3</div>
                    <div className={styles.stepContent}>
                        <h3>Swipe to Match</h3>
                        <p>We show you trailers. You vote Pass or Keep.</p>
                    </div>
                </div>
            </div>
        </div>
      </div>

      {/* Action Form (Right Panel) */}
      <div className={styles.rightPanel}>
        <motion.div 
            className={styles.formCard}
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ duration: 0.4, delay: 0.2 }}
        >
             {/* Mode Switch (Reusable Segmented Control) */}
             <div style={{ marginBottom: 24 }}>
                <SegmentedControl 
                    options={[
                        {  value: "create", label: "New Game" },
                        {  value: "join", label: "Join Game" }
                    ]}
                    value={mode}
                    onChange={(v) => setMode(v as any)}
                />
             </div>

            <motion.div 
                key={mode}
                initial={{ opacity: 0, x: 20 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ duration: 0.2 }}
            >
                <div className={styles.field}>
                    <Label>Your Name</Label>
                    <Input 
                        placeholder="e.g. Alex"
                        value={userName}
                        onChange={(e) => setUserName(e.target.value)}
                    />
                </div>

                {mode === "create" ? (
                <>
                    <div style={{ marginBottom: 24 }}>
                        <SegmentedControl 
                             options={[
                                { value: "movie", label: <><Film size={16} /> Movies</> },
                                { value: "tv", label: <><Smartphone size={16} /> TV Shows</> }
                             ]}
                             value={mediaType}
                             onChange={(v) => { setMediaType(v as any); setSelectedGenres([]); }}
                        />
                    </div>

                    <div className={styles.field}>
                        <Label>Where do you watch?</Label>
                        <div className={styles.pillsGrid}>
                            {PROVIDERS.map(p => (
                                <SelectionChip
                                    key={p.id}
                                    label={p.name}
                                    selected={selectedProviders.includes(p.id)}
                                    onClick={() => toggleProvider(p.id)}
                                />
                            ))}
                        </div>
                    </div>

                    <div className={styles.field}>
                        <Label>Genres</Label>
                        <div className={styles.pillsGrid}>
                            {currentGenres.map(g => (
                                <SelectionChip
                                    key={g.id}
                                    label={g.name}
                                    selected={selectedGenres.includes(g.id)}
                                    onClick={() => toggleGenre(g.id)}
                                />
                            ))}
                        </div>
                    </div>

                    <div className={styles.submitBtnWrapper}>
                      <Button3D 
                        variant="primary"
                        onClick={handleCreate}
                        disabled={!userName || selectedGenres.length === 0 || isSubmitting}
                        icon={<ArrowRight size={16} />}
                        className={styles.submitBtn}
                      >
                        {isSubmitting ? "Creating..." : "Start Matching"}
                      </Button3D>
                    </div>
                </>
                ) : (
                <>
                    <div className={styles.field}>
                        <Label>Room Code</Label>
                        <Input 
                            placeholder="ABCD"
                            maxLength={4}
                            value={roomCode}
                            onChange={(e) => setRoomCode(e.target.value.toUpperCase())}
                            className={styles.codeInput} // Keep style override for monospace
                        />
                    </div>

                    <div className={styles.submitBtnWrapper}>
                      <Button3D 
                        variant="secondary"
                        onClick={handleJoin}
                        disabled={!userName || roomCode.length !== 4 || isSubmitting}
                        icon={<ArrowRight size={16} />}
                        className="w-full"
                      >
                        {isSubmitting ? "Joining..." : "Enter Room"}
                      </Button3D>
                    </div>
                </>
                )}
            </motion.div>
        </motion.div>
      </div>
    </div>
  );
}

