import Image from "next/image";
import { motion, AnimatePresence } from "framer-motion";
import { useEffect, useState, useRef } from "react";
import { Magnetic } from "@/components/ui/Magnetic/Magnetic";
import { Button3D } from "@/components/ui/Button3D/Button3D";
import { TrailerModal } from "@/components/ui";
import styles from "./HeroSection.module.css";

interface HeroItem {
  id: number;
  title: string;
  overview: string;
  backdropPath: string | null;
  voteAverage: number;
  mediaType: "movie" | "tv";
  trailerKey?: string;
}

interface HeroSectionProps {
  items: HeroItem[];
  onItemClick?: (id: number, mediaType: "movie" | "tv") => void;
}

export function HeroSection({ items, onItemClick }: HeroSectionProps) {
  const [index, setIndex] = useState(0);
  const [showTrailer, setShowTrailer] = useState(false);
  const [progress, setProgress] = useState(0);
  const touchStartX = useRef(0);
  const touchEndX = useRef(0);

  const currentItem = items[index];
  const SLIDE_DURATION = 10000; // 10 seconds
  const SWIPE_THRESHOLD = 50; // minimum px for a swipe

  // Auto-rotate items with progress tracking
  useEffect(() => {
    if (showTrailer) return; // Pause while trailer modal is open

    const startTime = Date.now();

    const progressInterval = setInterval(() => {
      const elapsed = Date.now() - startTime;
      setProgress((elapsed / SLIDE_DURATION) * 100);
    }, 50);

    const timer = setTimeout(() => {
      setIndex((prev) => (prev + 1) % items.length);
      setProgress(0);
    }, SLIDE_DURATION);

    return () => {
      clearInterval(progressInterval);
      clearTimeout(timer);
    };
  }, [items.length, index, showTrailer]);

  // Handle indicator click
  const goToSlide = (slideIndex: number) => {
    setIndex(slideIndex);
    setProgress(0);
  };

  // Touch/swipe handlers for horizontal swipe navigation
  const handleTouchStart = (e: React.TouchEvent) => {
    touchStartX.current = e.touches[0].clientX;
    touchEndX.current = e.touches[0].clientX;
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    touchEndX.current = e.touches[0].clientX;
  };

  const handleTouchEnd = () => {
    const diff = touchStartX.current - touchEndX.current;
    if (Math.abs(diff) > SWIPE_THRESHOLD) {
      if (diff > 0) {
        // Swiped left → next slide
        setIndex((prev) => (prev + 1) % items.length);
      } else {
        // Swiped right → prev slide
        setIndex((prev) => (prev - 1 + items.length) % items.length);
      }
      setProgress(0);
    }
  };

  if (!currentItem) return null;

  return (
    <section
      className={styles.hero}
      onTouchStart={handleTouchStart}
      onTouchMove={handleTouchMove}
      onTouchEnd={handleTouchEnd}
    >
      <AnimatePresence mode="wait">
        <motion.div
          key={currentItem.id}
          className={styles.backdrop}
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          transition={{ duration: 1 }}
        >
          {currentItem.backdropPath && (
             <Image
                src={`https://image.tmdb.org/t/p/original${currentItem.backdropPath}`}
                alt={currentItem.title}
                fill
                className={styles.image}
                priority
              />
          )}
          <div className={styles.gradient} />
        </motion.div>
      </AnimatePresence>

      {/* Content */}
      <div className={styles.content}>
        <motion.div
           className={styles.info}
           initial={{ opacity: 0, y: 30 }}
           animate={{ opacity: 1, y: 0 }}
           transition={{ delay: 0.5, duration: 0.8 }}
        >
          <motion.h1 className={styles.title}>
            {currentItem.title}
          </motion.h1>

          <div className={styles.meta}>
            <span>{currentItem.mediaType === 'movie' ? 'Film' : 'Series'}</span>
            <span>•</span>
            <span>{currentItem.voteAverage.toFixed(1)} / 10</span>
          </div>

            <div className={styles.actions}>
              <Button3D 
                variant="primary"
                onClick={(e) => {
                  e.stopPropagation();
                  console.log("Trailer button clicked", currentItem);
                  if (currentItem.trailerKey) {
                    console.log("Opening trailer", currentItem.trailerKey);
                    setShowTrailer(true);
                  } else {
                    console.log("No trailer key, navigating");
                    onItemClick?.(currentItem.id, currentItem.mediaType);
                  }
                }}
                icon={
                  <svg viewBox="0 0 24 24" fill="currentColor" width="20" height="20">
                    <path d="M8 5v14l11-7z" />
                  </svg>
                }
              >
                Watch Trailer
              </Button3D>

              <Button3D 
                variant="secondary"
                onClick={(e) => {
                  e.stopPropagation();
                  onItemClick?.(currentItem.id, currentItem.mediaType);
                }}
                icon={
                  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" width="20" height="20">
                    <circle cx="12" cy="12" r="10" />
                    <path d="M12 16v-4M12 8h.01" />
                  </svg>
                }
              >
                More Info
              </Button3D>
            </div>
        </motion.div>
      </div>

      {/* Trailer Modal */}
      {showTrailer && currentItem.trailerKey && (
        <TrailerModal 
           trailerKey={currentItem.trailerKey}
           onClose={() => setShowTrailer(false)}
        />
      )}

      {/* Modern Slide Indicators - Vertical Lines on Right */}
      <div className={styles.slideIndicators}>
        {items.slice(0, 5).map((item, i) => (
          <button
            key={item.id}
            className={`${styles.slideIndicator} ${i === index ? styles.activeSlide : ""}`}
            onClick={() => goToSlide(i)}
            aria-label={`Go to slide ${i + 1}: ${item.title}`}
          >
            <span className={styles.indicatorTrack}>
              {i === index && (
                <motion.span 
                  className={styles.indicatorProgress}
                  initial={{ scaleY: 0 }}
                  animate={{ scaleY: progress / 100 }}
                  transition={{ duration: 0.05, ease: "linear" }}
                />
              )}
            </span>
            <span className={styles.indicatorNumber}>
              {String(i + 1).padStart(2, '0')}
            </span>
          </button>
        ))}
      </div>
    </section>
  );
}

"use client";

import { useRef, useState } from "react";
import { motion } from "framer-motion";

interface MagneticProps {
  children: React.ReactNode;
  strength?: number; // How far it moves (pixels)
  className?: string;
}

export function Magnetic({ children, strength = 30, className = "" }: MagneticProps) {
  const ref = useRef<HTMLDivElement>(null);
  const [position, setPosition] = useState({ x: 0, y: 0 });

  const handleMouseMove = (e: React.MouseEvent) => {
    const { clientX, clientY } = e;
    const { left, top, width, height } = ref.current!.getBoundingClientRect();

    const x = clientX - (left + width / 2);
    const y = clientY - (top + height / 2);

    setPosition({ x: x * 0.5, y: y * 0.5 });
  };

  const handleMouseLeave = () => {
    setPosition({ x: 0, y: 0 });
  };

  const { x, y } = position;

  return (
    <motion.div
      ref={ref}
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      animate={{ x, y }}
      transition={{ type: "spring", stiffness: 150, damping: 15, mass: 0.1 }}
      className={className}
    >
      {children}
    </motion.div>
  );
}

"use client";

import Image from "next/image";
import { motion } from "framer-motion";
import styles from "./MovieCard.module.css";
import { useState, useRef, useEffect } from "react";
import { MovieCardOverlay } from "./MovieCardOverlay";

interface MovieCardProps {
  id: number;
  title: string;
  posterPath: string | null;
  voteAverage: number;
  mediaType: "movie" | "tv";
  releaseDate?: string;
  onClick?: () => void;
}



export function MovieCard({
  id,
  title,
  posterPath,
  voteAverage,
  mediaType,
  releaseDate,
  onClick,
}: MovieCardProps) {
  const [isHovered, setIsHovered] = useState(false);
  const [showOverlay, setShowOverlay] = useState(false);
  const [rect, setRect] = useState<DOMRect | null>(null);
  const cardRef = useRef<HTMLElement>(null);
  const timerRef = useRef<NodeJS.Timeout>(null);
  const closeTimerRef = useRef<NodeJS.Timeout>(null);

  const imageUrl = posterPath
    ? `https://image.tmdb.org/t/p/w500${posterPath}`
    : "/placeholder-poster.png";

  useEffect(() => {
    return () => {
        if (timerRef.current) clearTimeout(timerRef.current);
        if (closeTimerRef.current) clearTimeout(closeTimerRef.current);
    };
  }, []);

  // Auto-close overlay on scroll
  useEffect(() => {
    if (!showOverlay) return;
    const handleScroll = () => {
      setShowOverlay(false);
      setRect(null);
      if (timerRef.current) clearTimeout(timerRef.current);
      if (closeTimerRef.current) clearTimeout(closeTimerRef.current);
    };
    window.addEventListener("scroll", handleScroll, { passive: true, capture: true });
    return () => window.removeEventListener("scroll", handleScroll, true);
  }, [showOverlay]);

  const handleMouseEnter = () => {
    setIsHovered(true);
    // Clear any pending close timer (if moving quickly between trigger and overlay)
    if (closeTimerRef.current) clearTimeout(closeTimerRef.current);

    // Start open timer if not already open
    if (!showOverlay) {
        timerRef.current = setTimeout(() => {
        if (cardRef.current) {
            setRect(cardRef.current.getBoundingClientRect());
            setShowOverlay(true);
        }
        }, 1250); // Increased to 1.25s to prevent accidental triggers
    }
  };

  const handleMouseLeave = () => {
     setIsHovered(false);
     if (timerRef.current) clearTimeout(timerRef.current);

     // Delay closing to allow entering the overlay
     closeTimerRef.current = setTimeout(() => {
         setShowOverlay(false);
         setRect(null); // Reset rect
     }, 300); // 300ms grace period
  };

  const handleOverlayMouseEnter = () => {
      // If we enter the overlay, cancel the close timer
      if (closeTimerRef.current) clearTimeout(closeTimerRef.current);
  };

  const handleOverlayMouseLeave = () => {
      // If we leave the overlay, start the close timer
      handleMouseLeave();
  };

  return (
    <>
      <article
        ref={cardRef}
        className={styles.card}
        onClick={onClick}
        onMouseEnter={handleMouseEnter}
        onMouseLeave={handleMouseLeave}
      >
        <div className={styles.imageWrapper}>
          <Image
            src={imageUrl}
            alt={title}
            fill
            sizes="(max-width: 480px) 50vw, (max-width: 768px) 33vw, (max-width: 1200px) 25vw, 20vw"
            className={styles.image}
          />
        </div>
      </article>

      {showOverlay && (
        <MovieCardOverlay
          isOpen={showOverlay}
          rect={rect}
          movie={{
            id,
            title,
            posterPath,
            voteAverage,
            mediaType,
            releaseDate
          }}
          onClose={handleOverlayMouseLeave}
          onMouseEnter={handleOverlayMouseEnter}
          onClick={() => onClick?.()}
        />
      )}
    </>
  );
}

