const TMDB_BASE_URL = "https://api.themoviedb.org/3";
const TMDB_API_KEY = process.env.TMDB_API_KEY;

export interface TMDBResult {
  id: number;
  title?: string;
  name?: string;
  poster_path: string | null;
  backdrop_path: string | null;
  vote_average: number;
  media_type?: "movie" | "tv";
  release_date?: string;
  first_air_date?: string;
  overview: string;
  trailerKey?: string;
  genre_ids?: number[];
}

export interface TMDBResponse {
  results: TMDBResult[];
  page: number;
  total_pages: number;
}

interface TMDBVideo {
  site: string;
  type: string;
  key: string;
  name: string;
}

interface TMDBGenre {
  id: number;
  name: string;
}

interface TMDBCastMember {
  id: number;
  name: string;
  profile_path: string | null;
  character: string;
}

interface TMDBCreator {
  id: number;
  name: string;
}

interface TMDBSeason {
  id: number;
  season_number: number;
  name: string;
  episode_count: number;
  poster_path: string | null;
  air_date: string | null;
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
interface TMDBDetailResponse {
  id: number;
  title?: string;
  name?: string;
  overview: string;
  poster_path: string | null;
  backdrop_path: string | null;
  vote_average: number;
  tagline?: string;
  status: string;
  runtime?: number;
  release_date?: string;
  first_air_date?: string;
  last_air_date?: string;
  budget?: number;
  revenue?: number;
  number_of_seasons?: number;
  number_of_episodes?: number;
  genres?: TMDBGenre[];
  seasons?: TMDBSeason[];
  created_by?: TMDBCreator[];
  credits?: { cast?: TMDBCastMember[] };
  videos?: { results?: TMDBVideo[] };
  similar?: { results?: TMDBResult[] };
  "watch/providers"?: Record<string, unknown>;
}

async function tmdbFetch<T>(endpoint: string, params: Record<string, string> = {}): Promise<T> {
  if (!TMDB_API_KEY) {
    console.error(`[TMDB] TMDB_API_KEY is missing in environment variables!`);
    throw new Error("TMDB_API_KEY is not set. Please configure it in your VERCEL environment variables (Settings -> Environment Variables).");
  }

  const url = new URL(`${TMDB_BASE_URL}${endpoint}`);
  url.searchParams.set("api_key", TMDB_API_KEY);
  Object.entries(params).forEach(([key, value]) => {
    url.searchParams.set(key, value);
  });

  try {
    const response = await fetch(url.toString(), { next: { revalidate: 3600 } }); 

    if (!response.ok) {
      throw new Error(`TMDB API error: ${response.status} ${response.statusText}`);
    }

    return response.json();
  } catch (error) {
    console.error(`[TMDB] Network/Fetch error for ${endpoint}:`, error);
    throw error;
  }
}

